payload.raw:
{
  "layout": "staggered-cards",
  "title": "核心研究的四大方向",
  "subtitle": "创新设计",
  "cards": [
    {
      "icon": "flask",
      "heading": "仿生柔性传感材料",
      "body": "基于仿水膜-鱼网结构的液态金属基导电薄膜与低迟滞聚氨酯介质复合材料，构建高灵敏度（应变系数>150）、低迟滞的柔性传感器阵列。"
    },
    {
      "icon": "cpu",
      "heading": "混合传感架构",
      "body": "融合光纤传感与惯性测量单元（IMU），构建混合传感架构，实现0.1mm级空间分辨率与毫秒级延迟的精准数据采集。"
    },
    {
      "icon": "brain",
      "heading": "高鲁棒手势识别算法",
      "body": "采用分层CNN-LSTM融合架构与自适应滑动窗口分割，显著提升复杂工况下的识别准确率（实测>98.2%）与抗抖动能力，实现毫秒级实时推理。"
    },
    {
      "icon": "zap",
      "heading": "高保真触觉反馈技术",
      "body": "集成微型电磁致动器阵列与半导体温控模块，实现对压力与温度参数的微秒级精准调控，逼近物理世界的交互质感。"
    }
  ]
}

