payload.raw:
{
  "layout": "list-featured",
  "title": "跨学科创新团队与技术基础",
  "subtitle": "创新基础",
  "cards": [
    {
      "icon": "users",
      "heading": "跨学科创新梯队",
      "body": "核心成员来自哈尔滨工业大学，专业背景深度融合材料科学、人工智能、算法设计与系统工程，构建了覆盖“感知-算法-交互-系统”全链条的研发团队。"
    },
    {
      "icon": "cpu",
      "heading": "顶尖科研平台支撑",
      "body": "依托哈工大智能人机交互研究中心，在高性能手势识别、多模态融合交互等方向长期布局，具备将柔性传感材料、信号处理与触觉反馈系统有机整合的工程化能力。"
    },
    {
      "icon": "award",
      "heading": "深厚科研积淀",
      "body": "累计发表IEEE Trans.等核心期刊论文50余篇，获授权国家发明专利10余项，核心技术经鉴定达“国际先进水平”，主持多项国家级课题。"
    },
    {
      "icon": "target",
      "heading": "自主技术体系",
      "body": "在柔性传感阵列设计、毫秒级交互延迟控制、视觉-触觉-动作多模态融合等方向形成自主技术体系，为突破高精度手势捕捉与真实感触觉反馈提供支撑。"
    },
    {
      "icon": "globe",
      "heading": "坚实技术底座",
      "body": "上述成果直接赋能项目，为“龙影元宇宙多模态智能数据手套”在硬件选型、算法优化及系统集成等关键环节提供坚实支撑，确保技术路径与元宇宙交互需求高度契合。"
    }
  ]
}

