payload.raw:
{
  "layout": "milestone-list",
  "title": "三年分阶段发展路径",
  "subtitle": "落地前景",
  "events": [
    {
      "date": "0–12个月",
      "title": "行业深耕期：价值验证与标杆打造",
      "description": "聚焦航空与国防领域，为中航光电、北方兵器研究所等标杆客户提供定制化“硬件+虚拟场景+量化评估”方案，完成价值验证，目标签约5家头部客户。依托85万元启动资金保障小试研发与试点交付。"
    },
    {
      "date": "12–24个月",
      "title": "区域拓展期：示范点建设与技术深化",
      "description": "联动哈工大智能人机交互研究中心，联合中国一重、哈电集团共建3个东北区域实训示范点。年度创新投入提升至营收15%，持续优化柔性传感阵列与多模态交互算法。"
    },
    {
      "date": "24个月后",
      "title": "全国复制期：生态构建与标准化推广",
      "description": "提炼标准化推广包，拓展轨道交通、能源装备等新赛道。通过开发者生态运营，推动高毛利软件服务占比提升至50%，构建“标杆引领—区域扎根—生态辐射”的可持续增长体系。"
    },
    {
      "date": "第5年",
      "title": "产业与区域经济贡献",
      "description": "预计实现总产值5亿元（硬件3亿元、软件与数据服务2亿元），创造地方税收超6000万元。累计产出发明专利20项、软件著作权15项及《航空装配实训白皮书》等行业标准成果。"
    },
    {
      "date": "长期影响",
      "title": "赋能产业升级与集群发展",
      "description": "推动区域企业培训成本降低40%、专家经验沉淀效率提升50%，加速实训体系向“虚实融合”智能化转型。联动本地职业院校共建产教融合基地，吸引50余家上下游企业集聚，培育XR交互装备产业集群，服务国家虚拟现实产业战略目标。"
    }
  ]
}

